app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

# Helper functions to load data

def load_users():
    users_path = os.path.join('data', 'users.txt')
    users = {}
    if os.path.exists(users_path):
        with open(users_path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 4:
                    username, email, phone, fullname = parts
                    users[username] = {
                        'username': username,
                        'email': email,
                        'phone': phone,
                        'fullname': fullname
                    }
    return users


def load_menu():
    menu_path = os.path.join('data', 'menu.txt')
    menu = []
    if os.path.exists(menu_path):
        with open(menu_path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 8:
                    dishid = int(parts[0])
                    name = parts[1]
                    category = parts[2]
                    price = parts[3]
                    description = parts[4]
                    ingredients = parts[5].split(',') if parts[5] else []
                    ingredients = [ing.strip() for ing in ingredients]
                    dietary = parts[6]
                    try:
                        avg_rating = float(parts[7])
                    except ValueError:
                        avg_rating = 0.0
                    menu.append({
                        'dishid': dishid,
                        'name': name,
                        'category': category,
                        'price': price,
                        'description': description,
                        'ingredients': ingredients,
                        'dietary': dietary,
                        'avg_rating': avg_rating
                    })
    return menu


def load_reservations():
    res_path = os.path.join('data', 'reservations.txt')
    reservations = []
    if os.path.exists(res_path):
        with open(res_path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 10:
                    try:
                        reservation_id = int(parts[0])
                        username = parts[1]
                        guestname = parts[2]
                        phone = parts[3]
                        emailaddr = parts[4]
                        partysize = int(parts[5])
                        date = parts[6]
                        time = parts[7]
                        specialrequests = parts[8]
                        status = parts[9]
                        reservations.append({
                            'reservation_id': reservation_id,
                            'username': username,
                            'guestname': guestname,
                            'phone': phone,
                            'emailaddr': emailaddr,
                            'partysize': partysize,
                            'date': date,
                            'time': time,
                            'specialrequests': specialrequests,
                            'status': status
                        })
                    except Exception:
                        continue
    return reservations


