        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 5:
                    try:
                        waitlistid = int(parts[0])
                        username = parts[1]
                        partysize = int(parts[2])
                        jointime = parts[3]
                        status = parts[4]
                        waitlist.append({
                            'waitlistid': waitlistid,
                            'username': username,
                            'partysize': partysize,
                            'jointime': jointime,
                            'status': status
                        })
                    except Exception:
                        continue
    return waitlist


def load_reviews():
    reviews = []
    path = os.path.join('data', 'reviews.txt')
    if os.path.exists(path):
        with open(path, 'r', encoding='utf-8') as f:
            for line in f:
                parts = line.strip().split('|')
                if len(parts) == 6:
                    try:
                        reviewid = int(parts[0])
                        username = parts[1]
                        dishid = int(parts[2])
                        rating = parts[3]
                        reviewtext = parts[4]
                        reviewdate = parts[5]
                        reviews.append({
                            'reviewid': reviewid,
                            'username': username,
                            'dishid': dishid,
                            'rating': rating,
                            'reviewtext': reviewtext,
                            'reviewdate': reviewdate
                        })
                    except Exception:
                        continue
    return reviews



